import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "How do I add hours and minutes?", a: "Add hours and minutes separately, then convert excess minutes to hours. Example: 2h 45m + 1h 30m = 3h 75m = 4h 15m (because 75 min = 1h 15m). This calculator handles the conversion automatically, including carrying over seconds into minutes and minutes into hours." },
  { q: "How do I convert hours to minutes?", a: "Multiply hours by 60. Examples: 2.5 hours = 150 minutes, 1.75 hours = 105 minutes, 0.25 hours = 15 minutes. To convert minutes to hours, divide by 60. 90 minutes = 1.5 hours, 45 minutes = 0.75 hours. For payroll, decimal hours are more useful than hours:minutes notation." },
  { q: "How many seconds are in an hour?", a: "1 hour = 60 minutes  x  60 seconds = 3,600 seconds. Useful time conversions: 1 day = 86,400 seconds, 1 week = 604,800 seconds, 1 year - 31,536,000 seconds (non-leap). Half a second = 500 milliseconds. Programs measure time in milliseconds (1/1000 second) or microseconds (1/1,000,000 second)." },
  { q: "How do I calculate elapsed time across midnight?", a: "If the time crosses midnight, add 24 hours to the end time. Example: start 11:30 PM (23:30), end 2:15 AM (02:15 next day). Convert end to 26:15, then: 26:15 - 23:30 = 2h 45m. Use the subtraction mode in this calculator - enter the start time as the first value and end time as the second." },
  { q: "How do I convert decimal hours to hours and minutes?", a: "Multiply the decimal portion by 60. Example: 2.75 hours - 2 hours + (0.75  x  60) = 2 hours 45 minutes. 1.33 hours - 1 hour + (0.33  x  60) = 1 hour 20 minutes. For time cards: 7.5 hours = 7 hours 30 minutes, 8.25 hours = 8 hours 15 minutes." },
  { q: "What is the difference between clock time and duration?", a: "Clock time (wall-clock time) refers to a specific moment: 3:00 PM. Duration is a length of time: 3 hours. You can add or subtract durations (3h + 2h = 5h). You can subtract clock times to get a duration (5:00 PM - 2:00 PM = 3 hours). You cannot add clock times (3:00 PM + 2:00 PM is meaningless). This calculator works with durations." },
  { q: "How do I add time for project management?", a: "For project time tracking: convert all estimates to a common unit (hours or minutes), add them, then convert back. Example: Task A (1h 30m) + Task B (2h 45m) + Task C (45m) = total 300 minutes = 5 hours. This calculator lets you add multiple time values sequentially." },
  { q: "How many minutes are in a day, week, or month?", a: "1 day = 1,440 minutes (60  x  24). 1 week = 10,080 minutes (1,440  x  7). 1 month (30 days) = 43,200 minutes. 1 year (365 days) = 525,600 minutes. A standard work year (2,080 hours) = 124,800 minutes. An 8-hour workday = 480 minutes." },
];

const TIME_CONVERSIONS = [
  ["1 minute", "60 seconds", "0.0167 hours"],
  ["30 minutes", "1,800 seconds", "0.5 hours"],
  ["1 hour", "3,600 seconds", "60 minutes"],
  ["90 minutes", "5,400 seconds", "1.5 hours"],
  ["8 hours", "28,800 seconds", "480 minutes"],
  ["1 day", "86,400 seconds", "1,440 minutes"],
  ["1 week", "604,800 seconds", "10,080 minutes"],
  ["1 year", "31,536,000 sec", "8,760 hours"],
];

function parseMins(h: number, m: number, s: number) { return h * 3600 + m * 60 + s; }
function fmtSec(totalSec: number) {
  const sign = totalSec < 0 ? "-" : "";
  const abs = Math.abs(totalSec);
  const h = Math.floor(abs / 3600);
  const m = Math.floor((abs % 3600) / 60);
  const s = abs % 60;
  return `${sign}${h}h ${String(m).padStart(2, "0")}m ${String(s).padStart(2, "0")}s`;
}

export default function TimeCalculator() {
  const [op, setOp] = useState<"add" | "sub">("add");
  const [h1, setH1] = useState(2); const [m1, setM1] = useState(30); const [s1, setS1] = useState(0);
  const [h2, setH2] = useState(1); const [m2, setM2] = useState(45); const [s2, setS2] = useState(0);

  const t1 = parseMins(h1, m1, s1);
  const t2 = parseMins(h2, m2, s2);
  const resultSec = op === "add" ? t1 + t2 : t1 - t2;

  const TimeInput = ({ h, m, s, setH, setM, setS, label }: { h: number; m: number; s: number; setH: (v: number) => void; setM: (v: number) => void; setS: (v: number) => void; label: string }) => (
    <div>
      <p className="text-sm font-semibold text-foreground mb-2">{label}</p>
      <div className="flex items-center gap-2">
        {[{ label: "h", val: h, set: setH, max: 999 }, { label: "m", val: m, set: setM, max: 59 }, { label: "s", val: s, set: setS, max: 59 }].map(({ label: l, val, set, max }) => (
          <div key={l} className="flex items-center gap-1">
            <input type="number" inputMode="numeric" min={0} max={max} value={val} onChange={e => set(Math.max(0, Math.min(max, Number(e.target.value))))} className="w-16 px-2 py-2 rounded-lg border border-input bg-background text-foreground text-center font-bold focus:outline-none focus:ring-2 focus:ring-primary/40" />
            <span className="text-sm text-muted-foreground">{l}</span>
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <>
      <SEOHead
        title="Free Time Calculator Online - Add and Subtract Time Instantly | CalcHive"
        description="Free online time calculator. Add or subtract hours, minutes and seconds with instant results. 100% free for everyone, works on all devices, no signup required."
        canonical="/time-calculator"
        keywords="free time calculator, add subtract hours minutes calculator free, time calculator online free, calculate time duration free, hours minutes seconds calculator free"
        category="Date & Time Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-slate-600 dark:text-slate-400 bg-slate-100 dark:bg-slate-800/50 px-3 py-1 rounded-full mb-4 inline-block">Tools</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Time Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free time calculator to add or subtract hours, minutes, and seconds instantly. This time calculator online free also works as an add subtract hours minutes calculator free, calculate time duration free, and hours minutes seconds calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="flex gap-2 mb-8">
            <button onClick={() => setOp("add")} className={`px-4 py-1.5 rounded-full text-sm font-semibold border transition-all ${op === "add" ? "bg-primary text-primary-foreground border-primary" : "bg-muted text-muted-foreground border-border"}`}>Add Time</button>
            <button onClick={() => setOp("sub")} className={`px-4 py-1.5 rounded-full text-sm font-semibold border transition-all ${op === "sub" ? "bg-primary text-primary-foreground border-primary" : "bg-muted text-muted-foreground border-border"}`}>Subtract Time</button>
          </div>
          <div className="space-y-6 mb-8">
            <TimeInput h={h1} m={m1} s={s1} setH={setH1} setM={setM1} setS={setS1} label="First Time" />
            <div className="text-center text-2xl font-black text-muted-foreground">{op === "add" ? "+" : "-"}</div>
            <TimeInput h={h2} m={m2} s={s2} setH={setH2} setM={setM2} setS={setS2} label="Second Time" />
          </div>
          <motion.div key={`${op}-${h1}-${m1}-${s1}-${h2}-${m2}-${s2}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-slate-600 to-slate-800 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Result</p>
              <p className="text-4xl font-black text-white tracking-tight" data-testid="result-time">{fmtSec(resultSec)}</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[
                { label: "Total Seconds", value: Math.abs(resultSec).toLocaleString() },
                { label: "Total Minutes", value: (Math.abs(resultSec) / 60).toFixed(2) },
                { label: "Decimal Hours", value: (Math.abs(resultSec) / 3600).toFixed(4) },
              ].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-lg font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Add and Subtract Hours Minutes and Seconds for Free</h2>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Convert all values to seconds: Total = (H  x  3600) + (M  x  60) + S</p>
            <p>Add or subtract totals in seconds</p>
            <p>Convert back: H = floor(result  x  3600)</p>
            <p>                M = floor((result mod 3600)  x  60)</p>
            <p>                S = result mod 60</p>
            <p className="text-xs text-muted-foreground mt-2">Decimal hours = Total seconds  x  3600</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Calculate Total Time Duration</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Duration", "Seconds", "Decimal Hours"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {TIME_CONVERSIONS.map(([dur, sec, hrs]) => (
                  <tr key={dur} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-bold text-foreground">{dur}</td>
                    <td className="py-2.5 px-4 text-slate-600 dark:text-slate-400 font-mono">{sec}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{hrs}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Time Addition Tool for Everyone</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free date and time tool on any device to compare schedules, track durations, and get instant results without signup.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/time-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


